/**
 * Protected regions for generated server files.
 *
 * `server.tsx` is fully regenerated by `generateServer()` on every
 * `shogo generate`. When a pod author (or the agent) edits it directly —
 * e.g. to add custom tenant-isolation middleware — the next regeneration
 * silently clobbers that code. The supported surface is `custom-routes.ts`,
 * but agents do put middleware in `server.tsx`, and losing a security guard
 * on a routine schema change is a P0.
 *
 * This module lets the generate path carry clearly-marked custom regions from
 * the existing file into the freshly generated one:
 *
 *   // SHOGO:CUSTOM-START
 *   ...custom code the generator must preserve...
 *   // SHOGO:CUSTOM-END
 */

export const CUSTOM_REGION_START = '// SHOGO:CUSTOM-START'
export const CUSTOM_REGION_END = '// SHOGO:CUSTOM-END'

export interface ProtectedRegion {
  /** Optional label after the START marker (e.g. `// SHOGO:CUSTOM-START tenant-guard`). */
  id: string
  /** Verbatim lines between the START and END markers (markers excluded). */
  body: string
}

/**
 * Extract every protected region from a source file. Pure parser — the START
 * marker may carry a trailing label which becomes the region `id`.
 */
export function extractProtectedRegions(content: string): ProtectedRegion[] {
  const lines = content.split('\n')
  const regions: ProtectedRegion[] = []

  let current: { id: string; body: string[] } | null = null
  for (const line of lines) {
    const trimmed = line.trim()
    if (trimmed.startsWith(CUSTOM_REGION_START)) {
      const id = trimmed.slice(CUSTOM_REGION_START.length).trim()
      current = { id, body: [] }
      continue
    }
    if (trimmed.startsWith(CUSTOM_REGION_END)) {
      if (current) {
        regions.push({ id: current.id, body: current.body.join('\n') })
        current = null
      }
      continue
    }
    if (current) current.body.push(line)
  }

  return regions
}

/**
 * Carry protected regions from an existing server file into a freshly
 * generated one so custom code survives regeneration.
 *
 * Strategy:
 *   - If the generated file already contains a region with the same id, its
 *     body is replaced with the preserved one (the markers in the template act
 *     as placeholders the author's code slots into).
 *   - Otherwise the preserved region is re-appended right before the final
 *     `export default` (or at end-of-file) so custom middleware survives even
 *     when the template has no slot for it.
 *
 * A no-op when `existing` has no protected regions.
 */
export function mergeProtectedRegions(existing: string, generated: string): string {
  const regions = extractProtectedRegions(existing)
  if (regions.length === 0) return generated

  const generatedRegionIds = new Set(extractProtectedRegions(generated).map(r => r.id))

  let out = generated
  const toAppend: string[] = []

  for (const region of regions) {
    const block = renderRegion(region)
    if (region.id && generatedRegionIds.has(region.id)) {
      out = replaceRegionBody(out, region)
    } else {
      toAppend.push(block)
    }
  }

  if (toAppend.length === 0) return out
  return insertBeforeDefaultExport(out, toAppend.join('\n\n'))
}

function renderRegion(region: ProtectedRegion): string {
  const start = region.id ? `${CUSTOM_REGION_START} ${region.id}` : CUSTOM_REGION_START
  return [start, region.body, CUSTOM_REGION_END].join('\n')
}

/** Replace the body of a same-id region already present in `content`. */
function replaceRegionBody(content: string, region: ProtectedRegion): string {
  const lines = content.split('\n')
  const out: string[] = []
  let inTarget = false

  for (const line of lines) {
    const trimmed = line.trim()
    if (!inTarget && trimmed.startsWith(CUSTOM_REGION_START) && trimmed.slice(CUSTOM_REGION_START.length).trim() === region.id) {
      inTarget = true
      out.push(line)
      out.push(region.body)
      continue
    }
    if (inTarget) {
      if (trimmed.startsWith(CUSTOM_REGION_END)) {
        inTarget = false
        out.push(line)
      }
      // drop the template's placeholder body lines
      continue
    }
    out.push(line)
  }

  return out.join('\n')
}

/** Insert `block` just before the final default export, else at end-of-file. */
function insertBeforeDefaultExport(content: string, block: string): string {
  const lines = content.split('\n')
  for (let i = lines.length - 1; i >= 0; i--) {
    if (/^\s*export\s+default\b/.test(lines[i])) {
      lines.splice(i, 0, block, '')
      return lines.join('\n')
    }
  }
  return `${content}\n\n${block}\n`
}
